def test_update_timesheet_missing_mandatory_field(base_url, hr_admin_token, audit_log_helper):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    payload = {"date": "2024-01-16", "project_id": "proj-124"}
    resp = <requests_patch>(f"{base_url}/api/timesheets/ts-002", json=payload, headers=headers)
    assert resp.status_code == 400
    assert "hours" in resp.json()["errors"][0]["field"].lower()
    audit = <audit_log_helper>(entity_id="ts-002", action="UPDATE")
    assert audit is None

def test_update_timesheet_unauthenticated(base_url):
    payload = {"hours": 35, "date": "2024-01-17", "project_id": "proj-125"}
    resp = <requests_patch>(f"{base_url}/api/timesheets/ts-003", json=payload)
    assert resp.status_code == 401
    assert "unauthorized" in resp.json()["message"].lower()

def test_update_timesheet_insufficient_role(base_url, employee_token):
    headers = {"Authorization": f"Bearer {employee_token}"}
    payload = {"hours": 38, "date": "2024-01-18", "project_id": "proj-126"}
    resp = <requests_patch>(f"{base_url}/api/timesheets/ts-004", json=payload, headers=headers)
    assert resp.status_code == 403
    assert "forbidden" in resp.json()["message"].lower() or "permission" in resp.json()["message"].lower()

def test_update_timesheet_boundary_hours_maximum(base_url, hr_admin_token):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    payload = {"hours": 24, "date": "2024-01-19", "project_id": "proj-127"}
    resp = <requests_patch>(f"{base_url}/api/timesheets/ts-005", json=payload, headers=headers)
    assert resp.status_code in [200, 201]
    assert resp.json()["hours"] == 24

def test_update_timesheet_boundary_hours_exceeds_maximum(base_url, hr_admin_token):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    payload = {"hours": 25, "date": "2024-01-20", "project_id": "proj-128"}
    resp = <requests_patch>(f"{base_url}/api/timesheets/ts-006", json=payload, headers=headers)
    assert resp.status_code == 400
