def test_update_timesheet_boundary_description_length(base_url, hr_admin_token):
    headers = {"Authorization": f"Bearer {hr_admin_token}"}
    max_desc = "x" * 500
    payload = {"hours": 8, "date": "2024-01-21", "project_id": "proj-129", "description": max_desc}
    resp = <requests_patch>(f"{base_url}/api/timesheets/ts-007", json=payload, headers=headers)
    assert resp.status_code in [200, 201]
    assert len(resp.json()["description"]) == 500
